1	import { useCallback, useSyncExternalStore } from "react";
2	import { Option, Schema } from "effect";
3	import { type ProviderKind, type ProviderServiceTier } from "@t3tools/contracts";
4	import { getDefaultModel, getModelOptions, normalizeModelSlug } from "@t3tools/shared/model";
5	
6	const APP_SETTINGS_STORAGE_KEY = "t3code:app-settings:v1";
7	const MAX_CUSTOM_MODEL_COUNT = 32;
8	export const MAX_CUSTOM_MODEL_LENGTH = 256;
9	export const APP_SERVICE_TIER_OPTIONS = [
10	  {
11	    value: "auto",
12	    label: "Automatic",
13	    description: "Use Codex defaults without forcing a service tier.",
14	  },
15	  {
16	    value: "fast",
17	    label: "Fast",
18	    description: "Request the fast service tier when the model supports it.",
19	  },
20	  {
21	    value: "flex",
22	    label: "Flex",
23	    description: "Request the flex service tier when the model supports it.",
24	  },
25	] as const;
26	export type AppServiceTier = (typeof APP_SERVICE_TIER_OPTIONS)[number]["value"];
27	const AppServiceTierSchema = Schema.Literals(["auto", "fast", "flex"]);
28	const MODELS_WITH_FAST_SUPPORT = new Set(["gpt-5.4"]);
29	const BUILT_IN_MODEL_SLUGS_BY_PROVIDER: Record<ProviderKind, ReadonlySet<string>> = {
30	  codex: new Set(getModelOptions("codex").map((option) => option.slug)),
31	};
32	
33	const AppSettingsSchema = Schema.Struct({
34	  codexBinaryPath: Schema.String.check(Schema.isMaxLength(4096)).pipe(
35	    Schema.withConstructorDefault(() => Option.some("")),
36	  ),
37	  codexHomePath: Schema.String.check(Schema.isMaxLength(4096)).pipe(
38	    Schema.withConstructorDefault(() => Option.some("")),
39	  ),
40	  confirmThreadDelete: Schema.Boolean.pipe(Schema.withConstructorDefault(() => Option.some(true))),
41	  enableAssistantStreaming: Schema.Boolean.pipe(
42	    Schema.withConstructorDefault(() => Option.some(false)),
43	  ),
44	  codexServiceTier: AppServiceTierSchema.pipe(Schema.withConstructorDefault(() => Option.some("auto"))),
45	  customCodexModels: Schema.Array(Schema.String).pipe(
46	    Schema.withConstructorDefault(() => Option.some([])),
47	  ),
48	});
49	export type AppSettings = typeof AppSettingsSchema.Type;
50	export interface AppModelOption {
51	  slug: string;
52	  name: string;
53	  isCustom: boolean;
54	}
55	
56	export function resolveAppServiceTier(serviceTier: AppServiceTier): ProviderServiceTier | null {
57	  return serviceTier === "auto" ? null : serviceTier;
58	}
59	
60	export function shouldShowFastTierIcon(
61	  model: string | null | undefined,
62	  serviceTier: AppServiceTier,
63	): boolean {
64	  const normalizedModel = normalizeModelSlug(model);
65	  return (
66	    resolveAppServiceTier(serviceTier) === "fast" &&
67	    normalizedModel !== null &&
68	    MODELS_WITH_FAST_SUPPORT.has(normalizedModel)
69	  );
70	}
71	
72	const DEFAULT_APP_SETTINGS = AppSettingsSchema.makeUnsafe({});
73	
74	let listeners: Array<() => void> = [];
75	let cachedRawSettings: string | null | undefined;
76	let cachedSnapshot: AppSettings = DEFAULT_APP_SETTINGS;
77	
78	export function normalizeCustomModelSlugs(
79	  models: Iterable<string | null | undefined>,
80	  provider: ProviderKind = "codex",
81	): string[] {
82	  const normalizedModels: string[] = [];
83	  const seen = new Set<string>();
84	  const builtInModelSlugs = BUILT_IN_MODEL_SLUGS_BY_PROVIDER[provider];
85	
86	  for (const candidate of models) {
87	    const normalized = normalizeModelSlug(candidate, provider);
88	    if (
89	      !normalized ||
90	      normalized.length > MAX_CUSTOM_MODEL_LENGTH ||
91	      builtInModelSlugs.has(normalized) ||
92	      seen.has(normalized)
93	    ) {
94	      continue;
95	    }
96	
97	    seen.add(normalized);
98	    normalizedModels.push(normalized);
99	    if (normalizedModels.length >= MAX_CUSTOM_MODEL_COUNT) {
100	      break;
101	    }
102	  }
103	
104	  return normalizedModels;
105	}
106	
107	function normalizeAppSettings(settings: AppSettings): AppSettings {
108	  return {
109	    ...settings,
110	    customCodexModels: normalizeCustomModelSlugs(settings.customCodexModels, "codex"),
111	  };
112	}
113	
114	export function getAppModelOptions(
115	  provider: ProviderKind,
116	  customModels: readonly string[],
117	  selectedModel?: string | null,
118	): AppModelOption[] {
119	  const options: AppModelOption[] = getModelOptions(provider).map(({ slug, name }) => ({
120	    slug,
121	    name,
122	    isCustom: false,
123	  }));
124	  const seen = new Set(options.map((option) => option.slug));
125	
126	  for (const slug of normalizeCustomModelSlugs(customModels, provider)) {
127	    if (seen.has(slug)) {
128	      continue;
129	    }
130	
131	    seen.add(slug);
132	    options.push({
133	      slug,
134	      name: slug,
135	      isCustom: true,
136	    });
137	  }
138	
139	  const normalizedSelectedModel = normalizeModelSlug(selectedModel, provider);
140	  if (normalizedSelectedModel && !seen.has(normalizedSelectedModel)) {
141	    options.push({
142	      slug: normalizedSelectedModel,
143	      name: normalizedSelectedModel,
144	      isCustom: true,
145	    });
146	  }
147	
148	  return options;
149	}
150	
151	export function resolveAppModelSelection(
152	  provider: ProviderKind,
153	  customModels: readonly string[],
154	  selectedModel: string | null | undefined,
155	): string {
156	  const options = getAppModelOptions(provider, customModels, selectedModel);
157	  const trimmedSelectedModel = selectedModel?.trim();
158	  if (trimmedSelectedModel) {
159	    const direct = options.find((option) => option.slug === trimmedSelectedModel);
160	    if (direct) {
161	      return direct.slug;
162	    }
163	
164	    const byName = options.find(
165	      (option) => option.name.toLowerCase() === trimmedSelectedModel.toLowerCase(),
166	    );
167	    if (byName) {
168	      return byName.slug;
169	    }
170	  }
171	
172	  const normalizedSelectedModel = normalizeModelSlug(selectedModel, provider);
173	  if (!normalizedSelectedModel) {
174	    return getDefaultModel(provider);
175	  }
176	
177	  return (
178	    options.find((option) => option.slug === normalizedSelectedModel)?.slug ??
179	    getDefaultModel(provider)
