/** Base mode determines `.dark` class and Tailwind `dark:` variant behavior. */
export type ThemeBase = "light" | "dark";

/** Concrete theme identifiers (excludes "system"). */
export type ConcreteThemeName = "t3-light" | "t3-dark" | "t3-midnight";

/** Theme selection value — includes "system" for auto-switching. */
export type ThemeName = ConcreteThemeName | "system";

/**
 * CSS custom property overrides for a theme.
 *
 * Keys are CSS variable names WITHOUT the leading `--`.
 * Values are valid CSS color strings (hex, oklch, rgb, etc.).
 *
 * Only overridden properties need to be specified — the base CSS
 * (`:root` for light, `@variant dark` for dark) provides all defaults.
 */
export interface ThemeColors {
  readonly background?: string;
  readonly foreground?: string;
  readonly card?: string;
  readonly "card-foreground"?: string;
  readonly popover?: string;
  readonly "popover-foreground"?: string;
  readonly primary?: string;
  readonly "primary-foreground"?: string;
  readonly secondary?: string;
  readonly "secondary-foreground"?: string;
  readonly muted?: string;
  readonly "muted-foreground"?: string;
  readonly accent?: string;
  readonly "accent-foreground"?: string;
  readonly destructive?: string;
  readonly "destructive-foreground"?: string;
  readonly border?: string;
