import { BUILTIN_THEMES, T3_DARK, T3_LIGHT, type ThemeDefinition, type ThemeName } from "@t3tools/shared/theme";
import { cn } from "../lib/utils";
import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch previews
// ---------------------------------------------------------------------------

function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  return (
    <div className="flex h-16 w-full flex-col overflow-hidden rounded-md border border-border">
      {theme.swatches.map((color, i) => (
        <div key={i} className="flex-1" style={{ backgroundColor: color }} />
      ))}
    </div>
  );
}

function SystemSwatch() {
  const leftSwatches = T3_LIGHT.swatches;
  const rightSwatches = T3_DARK.swatches;
  return (
    <div className="flex h-16 w-full overflow-hidden rounded-md border border-border">
      {/* Left half: light theme */}
      <div className="flex w-1/2 flex-col">
        {leftSwatches.map((color, i) => (
          <div key={i} className="flex-1" style={{ backgroundColor: color }} />
        ))}
      </div>
      {/* Right half: dark theme */}
      <div className="flex w-1/2 flex-col">
        {rightSwatches.map((color, i) => (
          <div key={i} className="flex-1" style={{ backgroundColor: color }} />
        ))}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Theme option card
// ---------------------------------------------------------------------------

function ThemeOptionCard({
  selected,
  label,
  description,
  onClick,
  children,
}: {
  selected: boolean;
  label: string;
  description: string;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={label}
      className={cn(
        "flex flex-col gap-2 rounded-lg border p-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
      )}
      onClick={onClick}
    >
      {children}
      <div className="flex w-full items-start justify-between gap-1">
        <span className="flex flex-col gap-0.5">
          <span className="text-xs font-medium text-foreground">{label}</span>
          <span className="text-[10px] leading-tight text-muted-foreground">{description}</span>
        </span>
        {selected ? (
          <span className="mt-0.5 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, setTheme, resolvedThemeDefinition } = useTheme();

  return (
    <div>
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">
          Choose a theme for T3 Code.
        </p>
      </div>

      <div
        className="grid grid-cols-2 gap-3 sm:grid-cols-4"
        role="radiogroup"
        aria-label="Theme preference"
      >
        {/* System option */}
        <ThemeOptionCard
          selected={theme === "system"}
          label="System"
          description="Match your OS appearance."
          onClick={() => setTheme("system" as ThemeName)}
        >
          <SystemSwatch />
        </ThemeOptionCard>

        {/* Built-in themes */}
        {BUILTIN_THEMES.map((t) => (
          <ThemeOptionCard
            key={t.name}
            selected={theme === t.name}
            label={t.label}
            description={t.description}
            onClick={() => setTheme(t.name)}
          >
            <ThemeSwatch theme={t} />
          </ThemeOptionCard>
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">
          {theme === "system"
            ? `System (${resolvedThemeDefinition.label})`
            : resolvedThemeDefinition.label}
        </span>
      </p>
    </div>
  );
}

