  readonly "sidebar-foreground"?: string;
  readonly editor?: string;
  readonly "editor-foreground"?: string;
  readonly terminal?: string;
  readonly "terminal-foreground"?: string;
  readonly "status-bar"?: string;
  readonly "status-bar-foreground"?: string;
}

/** Full theme definition. */
export interface ThemeDefinition {
  readonly name: ConcreteThemeName;
  readonly label: string;
  readonly description: string;
  /** Whether this theme applies the `.dark` class (for Tailwind `dark:` variants). */
  readonly base: ThemeBase;
  /** CSS variable overrides applied on top of the base light/dark defaults. */
  readonly colors: ThemeColors;
  /** Five preview swatch colors for the selector UI. */
  readonly swatches: readonly [string, string, string, string, string];
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

/**
 * T3 Light — the default light theme.
 *
 * Only defines new domain-specific variables (sidebar, editor, terminal,
 * status-bar). Standard variables inherit from the CSS `:root` block.
 */
export const T3_LIGHT: ThemeDefinition = {
  name: "t3-light",
  label: "T3 Light",
  description: "Clean light theme with the default T3 palette.",
  base: "light",
  colors: {
    sidebar: "#f8f8f8",
    "sidebar-foreground": "#1f1f1f",
    editor: "#ffffff",
    "editor-foreground": "#1f1f1f",
    terminal: "#f5f5f5",
    "terminal-foreground": "#1f1f1f",
    "status-bar": "#f0f0f0",
    "status-bar-foreground": "#6b7280",
  },
  swatches: ["#ffffff", "#1f1f1f", "#3b82f6", "#f8f8f8", "#f0f0f0"],
};

/**
 * T3 Dark — the default dark theme.
 *
 * Only defines new domain-specific variables. Standard variables inherit
 * from the CSS `@variant dark` block.
 */
export const T3_DARK: ThemeDefinition = {
  name: "t3-dark",
  label: "T3 Dark",
  description: "Default dark theme matching the current dark mode.",
  base: "dark",
  colors: {
    sidebar: "#141418",
    "sidebar-foreground": "#e5e5e5",
    editor: "#18181b",
    "editor-foreground": "#f5f5f5",
    terminal: "#111114",
    "terminal-foreground": "#d4d4d8",
    "status-bar": "#0f0f12",
    "status-bar-foreground": "#a1a1aa",
  },
  swatches: ["#18181b", "#f5f5f5", "#6d8af6", "#141418", "#0f0f12"],
};

/**
 * T3 Midnight — a deep blue-black theme for late-night coding.
 *
 * Overrides all standard variables to create a distinct palette with
 * blue-tinted accents on a deep dark base.
 */
export const T3_MIDNIGHT: ThemeDefinition = {
  name: "t3-midnight",
  label: "T3 Midnight",
  description: "Deep blue-black theme for late-night coding.",
  base: "dark",
  colors: {
    background: "#0b0e14",
    foreground: "#c8ccd4",
    card: "#0d1017",
    "card-foreground": "#c8ccd4",
    popover: "#0d1017",
    "popover-foreground": "#c8ccd4",
    primary: "#5599ff",
    "primary-foreground": "#ffffff",
    secondary: "rgba(255, 255, 255, 0.04)",
    "secondary-foreground": "#c8ccd4",
    muted: "rgba(255, 255, 255, 0.05)",
    "muted-foreground": "#6b7a8e",
    accent: "rgba(85, 153, 255, 0.12)",
    "accent-foreground": "#c8ccd4",
    destructive: "#f06565",
    "destructive-foreground": "#f09090",
    border: "rgba(255, 255, 255, 0.06)",
    input: "rgba(255, 255, 255, 0.08)",
    ring: "#5599ff",
    info: "#5599ff",
    "info-foreground": "#80b3ff",
    success: "#50c878",
    "success-foreground": "#70e898",
    warning: "#e8a838",
    "warning-foreground": "#f0c060",
    sidebar: "#080a10",
    "sidebar-foreground": "#b0b8c8",
    editor: "#0b0e14",
    "editor-foreground": "#c8ccd4",
    terminal: "#070910",
    "terminal-foreground": "#a0a8b8",
    "status-bar": "#060810",
    "status-bar-foreground": "#6b7a8e",
  },
  swatches: ["#0b0e14", "#c8ccd4", "#5599ff", "#080a10", "#060810"],
};

// ---------------------------------------------------------------------------
// Lookup helpers
// ---------------------------------------------------------------------------

/** Ordered array of all built-in themes. */
export const BUILTIN_THEMES: readonly ThemeDefinition[] = [
  T3_LIGHT,
  T3_DARK,
  T3_MIDNIGHT,
] as const;

/** Map for O(1) lookup by name. */
export const THEME_BY_NAME: ReadonlyMap<ConcreteThemeName, ThemeDefinition> = new Map(
  BUILTIN_THEMES.map((t) => [t.name, t]),
);

/** Type-guard for any valid `ThemeName` (including `"system"`). */
export function isThemeName(value: string): value is ThemeName {
  return value === "system" || THEME_BY_NAME.has(value as ConcreteThemeName);
}

/** Resolve `"system"` to the appropriate concrete theme based on OS preference. */
export function resolveTheme(name: ThemeName, prefersDark: boolean): ThemeDefinition {
  if (name === "system") {
    return prefersDark ? T3_DARK : T3_LIGHT;
  }
  return THEME_BY_NAME.get(name) ?? T3_DARK;
}

