import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type ThemeColors,
  type ThemeDefinition,
  type ThemeName,
  isThemeName,
  resolveTheme,
} from "@t3tools/shared/theme";

export type { ThemeName };

type ThemeSnapshot = {
  theme: ThemeName;
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read stored theme from localStorage, migrating legacy values.
 *
 * Old values: "light" -> "t3-light", "dark" -> "t3-dark", "system" stays.
 */
function getStored(): ThemeName {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === null) return "system";
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (isThemeName(raw)) return raw;
  return "system";
}

// ---------------------------------------------------------------------------
// CSS custom property management
// ---------------------------------------------------------------------------

/** Track which CSS vars were last applied so they can be cleaned up on switch. */
let appliedCssVarKeys: string[] = [];

function applyCssVars(colors: ThemeColors): void {
  const el = document.documentElement;

  // Remove previously applied overrides
  for (const key of appliedCssVarKeys) {
    el.style.removeProperty(`--${key}`);
  }

  // Apply new overrides
  const nextKeys: string[] = [];
  const entries = Object.entries(colors) as Array<[string, string | undefined]>;
  for (const [key, value] of entries) {
    if (value !== undefined) {
      el.style.setProperty(`--${key}`, value);
      nextKeys.push(key);
    }
  }
  appliedCssVarKeys = nextKeys;
}

// ---------------------------------------------------------------------------
// Theme application
// ---------------------------------------------------------------------------

function applyTheme(themeName: ThemeName, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const prefersDark = getSystemDark();
  const resolved = resolveTheme(themeName, prefersDark);

  // Toggle .dark class based on the theme's base — preserves Tailwind dark: variants
  document.documentElement.classList.toggle("dark", resolved.base === "dark");

  // Apply CSS custom property overrides
  applyCssVars(resolved.colors);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

// ---------------------------------------------------------------------------
// External store (useSyncExternalStore)
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (lastSnapshot && lastSnapshot.theme === theme && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;

  const resolvedThemeDefinition: ThemeDefinition = resolveTheme(
    theme,
    theme === "system" ? snapshot.systemDark : false,
  );

  const resolvedTheme: "light" | "dark" = resolvedThemeDefinition.base;

  const setTheme = useCallback((next: ThemeName) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, resolvedThemeDefinition } as const;
}

