25	const MODEL_PROVIDER_SETTINGS: Array<{
26	  provider: ProviderKind;
27	  title: string;
28	  description: string;
29	  placeholder: string;
30	  example: string;
31	}> = [
32	  {
33	    provider: "codex",
34	    title: "Codex",
35	    description: "Save additional Codex model slugs for the picker and `/model` command.",
36	    placeholder: "your-codex-model-slug",
37	    example: "gpt-6.7-codex-ultra-preview",
