39	] as const;
40	
41	function getCustomModelsForProvider(
42	  settings: ReturnType<typeof useAppSettings>["settings"],
43	  provider: ProviderKind,
44	) {
45	  switch (provider) {
46	    case "codex":
47	    default:
48	      return settings.customCodexModels;
49	  }
50	}
51	
52	function getDefaultCustomModelsForProvider(
53	  defaults: ReturnType<typeof useAppSettings>["defaults"],
54	  provider: ProviderKind,
55	) {
56	  switch (provider) {
57	    case "codex":
58	    default:
59	      return defaults.customCodexModels;
60	  }
61	}
62	
63	function patchCustomModels(provider: ProviderKind, models: string[]) {
64	  switch (provider) {
65	    case "codex":
66	    default:
