71	function SettingsRouteView() {
72	  const { settings, defaults, updateSettings } = useAppSettings();
73	  const serverConfigQuery = useQuery(serverConfigQueryOptions());
74	  const [isOpeningKeybindings, setIsOpeningKeybindings] = useState(false);
75	  const [openKeybindingsError, setOpenKeybindingsError] = useState<string | null>(null);
76	  const [customModelInputByProvider, setCustomModelInputByProvider] = useState<
77	    Record<ProviderKind, string>
78	  >({
79	    codex: "",
80	  });
81	  const [customModelErrorByProvider, setCustomModelErrorByProvider] = useState<
82	    Partial<Record<ProviderKind, string | null>>
83	  >({});
84	
85	  const codexBinaryPath = settings.codexBinaryPath;
86	  const codexHomePath = settings.codexHomePath;
87	  const codexServiceTier = settings.codexServiceTier;
88	  const keybindingsConfigPath = serverConfigQuery.data?.keybindingsConfigPath ?? null;
89	
90	  const openKeybindingsFile = useCallback(() => {
91	    if (!keybindingsConfigPath) return;
92	    setOpenKeybindingsError(null);
93	    setIsOpeningKeybindings(true);
94	    const api = ensureNativeApi();
95	    void api.shell
96	      .openInEditor(keybindingsConfigPath, preferredTerminalEditor())
97	      .catch((error) => {
98	        setOpenKeybindingsError(
99	          error instanceof Error ? error.message : "Unable to open keybindings file.",
100	        );
101	      })
102	      .finally(() => {
103	        setIsOpeningKeybindings(false);
104	      });
105	  }, [keybindingsConfigPath]);
106	
107	  const addCustomModel = useCallback((provider: ProviderKind) => {
108	    const customModelInput = customModelInputByProvider[provider];
109	    const customModels = getCustomModelsForProvider(settings, provider);
110	    const normalized = normalizeModelSlug(customModelInput, provider);
111	    if (!normalized) {
112	      setCustomModelErrorByProvider((existing) => ({
113	        ...existing,
114	        [provider]: "Enter a model slug.",
115	      }));
116	      return;
117	    }
118	    if (getModelOptions(provider).some((option) => option.slug === normalized)) {
119	      setCustomModelErrorByProvider((existing) => ({
120	        ...existing,
121	        [provider]: "That model is already built in.",
122	      }));
123	      return;
124	    }
125	    if (normalized.length > MAX_CUSTOM_MODEL_LENGTH) {
126	      setCustomModelErrorByProvider((existing) => ({
127	        ...existing,
128	        [provider]: `Model slugs must be ${MAX_CUSTOM_MODEL_LENGTH} characters or less.`,
129	      }));
130	      return;
131	    }
132	    if (customModels.includes(normalized)) {
133	      setCustomModelErrorByProvider((existing) => ({
134	        ...existing,
135	        [provider]: "That custom model is already saved.",
136	      }));
137	      return;
138	    }
139	
140	    updateSettings(patchCustomModels(provider, [...customModels, normalized]));
141	    setCustomModelInputByProvider((existing) => ({
142	      ...existing,
143	      [provider]: "",
144	    }));
145	    setCustomModelErrorByProvider((existing) => ({
146	      ...existing,
147	      [provider]: null,
148	    }));
149	  }, [customModelInputByProvider, settings, updateSettings]);
150	
151	  const removeCustomModel = useCallback(
152	    (provider: ProviderKind, slug: string) => {
153	      const customModels = getCustomModelsForProvider(settings, provider);
154	      updateSettings(patchCustomModels(provider, customModels.filter((model) => model !== slug)));
155	      setCustomModelErrorByProvider((existing) => ({
156	        ...existing,
157	        [provider]: null,
158	      }));
159	    },
160	    [settings, updateSettings],
161	  );
162	
163	  return (
164	    <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground isolate">
165	      <div className="flex min-h-0 min-w-0 flex-1 flex-col bg-background text-foreground">
166	        {isElectron && (
167	          <div className="drag-region flex h-[52px] shrink-0 items-center border-b border-border px-5">
168	            <span className="text-xs font-medium tracking-wide text-muted-foreground/70">
169	              Settings
170	            </span>
171	          </div>
172	        )}
173	
174	        <div className="flex-1 overflow-y-auto p-6">
175	          <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
176	            <header className="space-y-1">
177	              <h1 className="text-2xl font-semibold tracking-tight text-foreground">Settings</h1>
178	              <p className="text-sm text-muted-foreground">
179	                Configure app-level preferences for this device.
180	              </p>
181	            </header>
182	
183	            <section className="rounded-2xl border border-border bg-card p-5">
184	              <ThemeSelector />
185	            </section>
186	
187	            <section className="rounded-2xl border border-border bg-card p-5">
188	              <div className="mb-4">
189	                <h2 className="text-sm font-medium text-foreground">Codex App Server</h2>
190	                <p className="mt-1 text-xs text-muted-foreground">
191	                  These overrides apply to new sessions and let you use a non-default Codex install.
192	                </p>
193	              </div>
194	
195	              <div className="space-y-4">
196	                <label htmlFor="codex-binary-path" className="block space-y-1">
197	                  <span className="text-xs font-medium text-foreground">Codex binary path</span>
198	                  <Input
199	                    id="codex-binary-path"
200	                    value={codexBinaryPath}
201	                    onChange={(event) => updateSettings({ codexBinaryPath: event.target.value })}
202	                    placeholder="codex"
203	                    spellCheck={false}
204	                  />
205	                  <span className="text-xs text-muted-foreground">
206	                    Leave blank to use <code>codex</code> from your PATH.
207	                  </span>
208	                </label>
209	
210	                <label htmlFor="codex-home-path" className="block space-y-1">
211	                  <span className="text-xs font-medium text-foreground">CODEX_HOME path</span>
212	                  <Input
213	                    id="codex-home-path"
214	                    value={codexHomePath}
215	                    onChange={(event) => updateSettings({ codexHomePath: event.target.value })}
216	                    placeholder="/Users/you/.codex"
217	                    spellCheck={false}
218	                  />
219	                  <span className="text-xs text-muted-foreground">
220	                    Optional custom Codex home/config directory.
221	                  </span>
222	                </label>
223	
224	                <div className="flex items-center justify-between gap-2 text-xs text-muted-foreground">
225	                  <p>
226	                    Binary source:{" "}
227	                    <span className="font-medium text-foreground">{codexBinaryPath || "PATH"}</span>
228	                  </p>
229	                  <Button
230	                    size="xs"
231	                    variant="outline"
232	                    onClick={() =>
233	                      updateSettings({
234	                        codexBinaryPath: defaults.codexBinaryPath,
