265	                      updateSettings({ codexServiceTier: value });
266	                    }}
267	                  >
268	                    <SelectTrigger>
269	                      <SelectValue />
270	                    </SelectTrigger>
271	                    <SelectPopup alignItemWithTrigger={false}>
272	                      {APP_SERVICE_TIER_OPTIONS.map((option) => (
273	                        <SelectItem key={option.value} value={option.value}>
274	                          <div className="flex min-w-0 items-center gap-2">
275	                            {option.value === "fast" ? (
